async (params, browser) => {
  // Search TripAdvisor for hotels
  await browser.open(`https://www.tripadvisor.com/Search?q=${params.destination}+hotels`)

  // Wait for search results
  await browser.waitForSelector('[data-test-target=\'search-result\'], .result-title, .search-results-list', 15000)

  // Let results render
  await browser.wait(3000)

  // Click through to hotel listings
  const click_hotels = await browser.evaluate(`const hotelLink = document.querySelector('a[href*="Hotels-g"], a[href*="Hotels-"], [data-test-target="search-result"] a[href*="Hotel"]'); if (hotelLink) { hotelLink.click(); } return { clicked: !!hotelLink }`)

  // Wait for hotel listings page
  await browser.wait(4000)

  // Wait for hotel cards to load
  await browser.waitForSelector('[data-test-target=\'property-card\'], .property_title, .listing_title, [class*=\'HotelCard\']', 15000)

  // Scroll to load more hotels
  await browser.scroll({ direction: 'down', amount: 1500 })

  await browser.wait(2000)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1500 })

  await browser.wait(2000)

  // Scroll for more results
  await browser.scroll({ direction: 'down', amount: 1500 })

  await browser.wait(2000)

  // Extract hotel comparison data
  const comparison_results = await browser.evaluate(`const hotels = []; const cards = document.querySelectorAll('[data-test-target="property-card"], .prw_rup, [class*="HotelCard"], [class*="listItem"], div[data-automation="hotel-card"]'); for (let i = 0; i < Math.min(cards.length, 15); i++) { const el = cards[i]; const nameEl = el.querySelector('.listing_title a, .property_title a, a[class*="property_title"], [data-test-target="property-title"] a, [class*="hotelName"], a[href*="Hotel_Review"]'); const name = nameEl ? nameEl.textContent.trim() : ''; if (!name) continue; const url = nameEl ? (nameEl.href.startsWith('http') ? nameEl.href : 'https://www.tripadvisor.com' + nameEl.getAttribute('href')) : ''; const ratingEl = el.querySelector('svg[aria-label*="bubble"], .ui_bubble_rating, [class*="ratingValue"]'); const rating = ratingEl ? (ratingEl.getAttribute('aria-label') || ratingEl.textContent.trim() || '') : ''; const reviewCountEl = el.querySelector('[class*="reviewCount"], a[href*="#REVIEWS"] span, [class*="review_count"]'); const reviewCount = reviewCountEl ? reviewCountEl.textContent.trim() : ''; const priceEl = el.querySelector('[data-test-target="price-summary"], [class*="price"], .price, [class*="priceValue"]'); const price = priceEl ? priceEl.textContent.trim() : ''; const starsEl = el.querySelector('[class*="hotelClass"], [class*="starRating"], svg[aria-label*="star"], .ui_star_rating'); const stars = starsEl ? (starsEl.getAttribute('aria-label') || starsEl.textContent.trim() || '') : ''; const amenityEls = el.querySelectorAll('[class*="amenity"] span, [class*="tag"] span'); const amenities = []; for (const a of amenityEls) { const text = a.textContent.trim(); if (text && text.length < 40 && !amenities.includes(text)) amenities.push(text); } const imgEl = el.querySelector('img[src*="photo"], img[src*="media"], img[data-lazyurl]'); const image = imgEl ? (imgEl.getAttribute('src') || imgEl.getAttribute('data-lazyurl') || '') : ''; hotels.push({ name: name, price: price, rating: rating, review_count: reviewCount, star_class: stars, amenity_highlights: amenities.slice(0, 5), image: image, url: url }); } return { destination: params.destination, hotel_count: hotels.length, hotels: hotels }`)

  return comparison_results
}
